SELECT ?person ?birthDate WHERE {
  ?person wdt:P39 wd:Q1019672;
           wdt:P1082 wd:Q26270;
           wdt:P569 ?birthDate.
  ?person wdt:P102 ?party.
}
GROUP BY ?person ?birthDate
HAVING (COUNT(?party) >= 2)
ORDER BY ASC(?birthDate)
LIMIT 2

